import { Gizmo } from "@gizmo/runtime";

export default class CrystalSpin {
  t = 0;
  baseY = 0.6;
  start(self: any) {
    this.baseY = self.transform.position[1];
    this.t = Math.random() * 6;
  }
  update(self: any, dt: number) {
    this.t += dt;
    self.transform.rotation[1] += dt * 90;
    self.transform.position[1] = this.baseY + Math.sin(this.t * 2) * 0.15;
  }
}

import { Gizmo } from "@gizmo/runtime";

let totalScore = 0;

export default class CrystalCollect {
  constructor() {
    (this as any)._base = 0;
    (this as any)._t = Math.random() * 6.28;
  }

  start(self: any) {
    (this as any)._base = self.transform.position[1];
  }

  update(self: any, dt: number) {
    (this as any)._t += dt * 1.6;
    self.transform.rotation[1] += dt * 1.8;
    self.transform.position[1] = (this as any)._base + Math.sin((this as any)._t) * 0.25;
  }

  onTriggerEnter(self: any, other: any) {
    if (other.tag !== "Player") return;
    totalScore += 10;
    Gizmo.ui.set("Score", totalScore + " pts");
    if (totalScore >= 60) {
      Gizmo.ui.set("Mission", "COMPLETE ✓");
    }
    self.destroy();
  }
}

import { Gizmo } from "@gizmo/runtime";

let totalScore = 0;

export default class OrbitDrone {
  constructor() {
    (this as any)._angle = Math.random() * 6.28;
  }

  update(self: any, dt: number) {
    let radius = 8;
    let altitude = 2;
    let speed = 0.6;

    if (self.name === "Drone 2") {
      radius = 12;
      altitude = 3.5;
      speed = 0.4;
    }

    (this as any)._angle += dt * speed;
    const angle = (this as any)._angle;
    self.transform.position[0] = Math.cos(angle) * radius;
    self.transform.position[1] = altitude;
    self.transform.position[2] = Math.sin(angle) * radius;
  }

  onTriggerEnter(self: any, other: any) {
    if (other.tag !== "Player") return;
    totalScore = 0;
    Gizmo.ui.set("Score", "0 pts");
    Gizmo.ui.set("Alert", "⚠ Drone hit! Score reset");
  }
}

import { Gizmo } from "@gizmo/runtime";

let totalScore = 0;
let collected = 0;

export default class CrystalCollect {
  constructor() {
    (this as any)._base = 0;
    (this as any)._t = Math.random() * 6.28;
  }

  start(self: any) {
    (this as any)._base = self.transform.position[1];
  }

  update(self: any, dt: number) {
    (this as any)._t += dt * 1.6;
    self.transform.rotation[1] += dt * 1.8;
    self.transform.position[1] =
      (this as any)._base + Math.sin((this as any)._t) * 0.25;
  }

  onTriggerEnter(self: any, other: any) {
    if (other.tag !== "Player") return;
    totalScore += 10;
    collected += 1;
    Gizmo.ui.set("Score", totalScore + " pts");
    if (collected >= 6) {
      Gizmo.ui.set("Mission", "COMPLETE ✓ You win!");
    }
    self.destroy();
  }
}

import { Gizmo } from "@gizmo/runtime";

let totalScore = 0;

export default class OrbitDrone {
  constructor() {
    (this as any)._angle = Math.random() * 6.28;
  }

  start(self: any) {
    // Drone 1 orbits at radius 8, y=2; Drone 2 at radius 12, y=3.5
    if (self.name === "Drone 1") {
      (this as any)._radius = 8;
      (this as any)._altitude = 2;
      (this as any)._speed = 0.6;
    } else {
      (this as any)._radius = 12;
      (this as any)._altitude = 3.5;
      (this as any)._speed = 0.38;
    }
  }

  update(self: any, dt: number) {
    (this as any)._angle += dt * (this as any)._speed;
    const r = (this as any)._radius;
    const a = (this as any)._angle;
    self.transform.position[0] = Math.cos(a) * r;
    self.transform.position[1] = (this as any)._altitude;
    self.transform.position[2] = Math.sin(a) * r;
    // Spin the drone for visual effect
    self.transform.rotation[1] += dt * 3.0;
  }

  onTriggerEnter(self: any, other: any) {
    if (other.tag !== "Player") return;
    totalScore = 0;
    Gizmo.ui.set("Score", "0 pts");
    Gizmo.ui.set("Alert", "⚠ Drone hit! Score reset");
  }
}
